def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    base_factor = np.pi
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                term = np.sin(ratio * a * base_factor) * (a ** 3) / (a + 2)
                if a % 4 == 0:
                    term *= 0.85
                else:
                    term *= 1.1
                score += term
            adjustment = 0
            for k in range(1, 8):
                adjustment += np.cos(ratio * k * 2 * base_factor) / (k + 0.5)
            if int(capacity * item) % 9 == 0:
                score *= 0.9 + 0.05 * adjustment
            else:
                score += adjustment * 1.7
            if score > 12:
                score /= (ratio + 1.7)
        elif 0.05 <= ratio < 0.2:
            product = 1.0
            for n in range(1, int(capacity) + 3):
                add_val = (ratio + (n - 1)**0.7 / (n + ratio))
                product *= max(0.7, min(add_val, 1.5))
                if product > 5e5:
                    product = np.log1p(product*1.2)
                    break
            mod_val = int(product * 3) % 250
            score = np.log1p(ratio * mod_val + 1) * 2.5
            if (int(capacity) % 5 == 0) and (int(item * 7) % 4 ==0):
                score *= 1.1
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x**3) % 1) * (x ** 2.3)
                if x % 2 == 0:
                    val *= 1.15
                extra_sum += val
            score += extra_sum / 8
        elif 0.2 <= ratio <= 0.5:
            sum_val = 0
            for m in range(1, 10):
                pow_base = ratio ** (m + 1.5)
                exp_base = np.exp(-m/5)
                sum_val += pow_base * (m ** 3.1) * exp_base
            remainder = capacity - item
            if remainder < 4:
                sum_val += 15 + remainder * 0.7
            else:
                sum_val -= remainder * 1.1
            if sum_val < -7:
                sum_val = abs(sum_val) * 0.4 + 3
            if int(capacity) % 8 == 0:
                sum_val *= 1.3
            if sum_val > 20:
                sum_val /= 4
            score = sum_val
        elif 0.5 < ratio <= 0.85:
            penalty = 0
            for p in range(1, 15):
                term = ((ratio - 0.5) ** p) * (p ** 2.9) / (p + 0.7)
                penalty += term
                if penalty > 80:
                    penalty = np.log1p(penalty)*1.3
                    break
            score = penalty * 9
            if capacity < item * 1.07:
                score += 18
            if (int(capacity * 4) % 6 == 0) and (int(item * 9) % 8 == 0):
                score -= 8
            if score < -3:
                score = abs(score) * 1.2 + 6
            if score > 130:
                score = 130
            for z in range(1, 8):
                score += ((ratio / (z + 0.3)) % 1) * (z * 1.9)
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 16):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 1.1)
                if penalty_ext > 1500:
                    penalty_ext = np.sqrt(penalty_ext)*1.4
                    break
            score = penalty_ext * 11
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 7) % 5 == 0) and (int(item * 12) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.8)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.8
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 15000:
                    term = np.cbrt(term) * 2.1
                super_penalty += term
            score = super_penalty * 18
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 3 == 0) and (int(item * 21) % 6 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.75 + 7
            if score > 3000:
                score = 3000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q10, q25, q50, q75, q90 = np.percentile(finite_priorities, [10, 25, 50, 75, 90])
        top_count = np.sum(finite_priorities > q90)
        mid_count = np.sum((finite_priorities >= q25) & (finite_priorities <= q75))
        median_val = q50
        fill_value = (np.max(finite_priorities) * (20 + top_count) - median_val) / max(mid_count, 1)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
